use Text::File;

print "Enter filename: ";
my $filename = standard_in;
$content = Text::File->read($filename)->content;

email_list = [];

for (my $line = $content; $line; $line++) {
    if (match('/\b[A-Za-z][A-Z0-9._-]+@([A-Za-z][A-Z0-9.-_]{0,2}[A-Za-z]{2})?$/u', $line)) {
        email_list[-1] = $line;
    }
}

text = join('\n', email_list);
